function MovieList({ movies, onDelete }) {
    return (

        <div>
            <h2> Movie List</h2>
            <ul>
                {movies.map((movie) => (

                    <li Key={movie.id}>{movie.title}
                        <button onClick={() => onDelete(movie.id)}>Delete</button> </li>
                ))}
            </ul>
        </div>
    );

}

export default MovieList;
